import{c as e,Q as i,j as l,m as t}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"Web 开发文档写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"webLearning/00-写作计划.md","filePath":"webLearning/00-写作计划.md","lastUpdated":1780901419000}'),s={name:"webLearning/00-写作计划.md"};function n(o,a,r,d,c,h){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="web-开发文档写作计划" tabindex="-1">Web 开发文档写作计划 <a class="header-anchor" href="#web-开发文档写作计划" aria-label="Permalink to &quot;Web 开发文档写作计划&quot;">​</a></h1><p>已整理为 43 篇。主线不再追求&quot;把所有框架都讲一遍&quot;,而是围绕现代前端真正常用的三层能力展开:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础能力(CSS / TS / JS / 浏览器)</span></span>
<span class="line"><span>  -&gt; 主力框架(React / Vue)</span></span>
<span class="line"><span>  -&gt; 响应式对照(SolidJS)</span></span>
<span class="line"><span>  -&gt; 工程化与生产专题</span></span></code></pre></div><p>一句话:<strong>前端不是框架 API 合集,而是 UI 状态、浏览器平台、工程化链路和生产交付的组合。</strong></p><hr><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><h3 id="第一层-入口与-react-主线-01-10" tabindex="-1">第一层:入口与 React 主线(01-10) <a class="header-anchor" href="#第一层-入口与-react-主线-01-10" aria-label="Permalink to &quot;第一层:入口与 React 主线(01-10)&quot;">​</a></h3><ul><li>[x] 01 前端学习路线总览</li><li>[x] 02 React 总览与心智</li><li>[x] 03 JSX 与组件</li><li>[x] 04 Hooks 详解</li><li>[x] 05 React 状态管理</li><li>[x] 06 React 路由</li><li>[x] 07 React 数据获取</li><li>[x] 08 React 表单</li><li>[x] 09 React 性能与渲染机制</li><li>[x] 10 Next.js</li></ul><h3 id="第二层-vue-主线-11-17" tabindex="-1">第二层:Vue 主线(11-17) <a class="header-anchor" href="#第二层-vue-主线-11-17" aria-label="Permalink to &quot;第二层:Vue 主线(11-17)&quot;">​</a></h3><ul><li>[x] 11 Vue 总览与心智</li><li>[x] 12 Vue 模板与指令</li><li>[x] 13 Vue 组合式 API</li><li>[x] 14 Vue 响应式原理</li><li>[x] 15 Pinia</li><li>[x] 16 Vue Router</li><li>[x] 17 Nuxt</li></ul><h3 id="第三层-solidjs-响应式对照-18-21" tabindex="-1">第三层:SolidJS 响应式对照(18-21) <a class="header-anchor" href="#第三层-solidjs-响应式对照-18-21" aria-label="Permalink to &quot;第三层:SolidJS 响应式对照(18-21)&quot;">​</a></h3><ul><li>[x] 18 SolidJS 总览与心智</li><li>[x] 19 SolidJS Signals 与细粒度响应式</li><li>[x] 20 SolidJS Stores 与进阶响应式</li><li>[x] 21 SolidStart</li></ul><h3 id="第四层-基础能力-22-25" tabindex="-1">第四层:基础能力(22-25) <a class="header-anchor" href="#第四层-基础能力-22-25" aria-label="Permalink to &quot;第四层:基础能力(22-25)&quot;">​</a></h3><ul><li>[x] 22 CSS 布局:Flexbox 与 Grid</li><li>[x] 23 CSS 方案全景:Tailwind / CSS Modules / styled-components</li><li>[x] 24 TypeScript 类型系统深入</li><li>[x] 25 JavaScript 异步与事件循环</li></ul><h3 id="第五层-工程化与全栈闭环-26-31" tabindex="-1">第五层:工程化与全栈闭环(26-31) <a class="header-anchor" href="#第五层-工程化与全栈闭环-26-31" aria-label="Permalink to &quot;第五层:工程化与全栈闭环(26-31)&quot;">​</a></h3><ul><li>[x] 26 构建工具与工程化</li><li>[x] 27 测试体系</li><li>[x] 28 认证与安全</li><li>[x] 29 Node.js 后端入门</li><li>[x] 30 数据库与 ORM</li><li>[x] 31 部署与 CI/CD</li></ul><h3 id="第六层-浏览器与运行时能力-32-35" tabindex="-1">第六层:浏览器与运行时能力(32-35) <a class="header-anchor" href="#第六层-浏览器与运行时能力-32-35" aria-label="Permalink to &quot;第六层:浏览器与运行时能力(32-35)&quot;">​</a></h3><ul><li>[x] 32 Web 性能优化</li><li>[x] 33 实时通信:WebSocket 与 SSE</li><li>[x] 34 PWA 与 Service Worker</li><li>[x] 35 浏览器渲染原理</li></ul><h3 id="第七层-专题-36-43" tabindex="-1">第七层:专题(36-43) <a class="header-anchor" href="#第七层-专题-36-43" aria-label="Permalink to &quot;第七层:专题(36-43)&quot;">​</a></h3><ul><li>[x] 36 WebAssembly 入门</li><li>[x] 37 Web Components</li><li>[x] 38 微前端架构</li><li>[x] 39 图形与动画</li><li>[x] 40 无障碍 a11y</li><li>[x] 41 国际化 i18n</li><li>[x] 42 桌面端:Electron 与 Tauri</li><li>[x] 43 跨端:React Native 与 Capacitor</li></ul><hr><h2 id="推荐读法" tabindex="-1">推荐读法 <a class="header-anchor" href="#推荐读法" aria-label="Permalink to &quot;推荐读法&quot;">​</a></h2><h3 id="新人路线" tabindex="-1">新人路线 <a class="header-anchor" href="#新人路线" aria-label="Permalink to &quot;新人路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 22 -&gt; 23 -&gt; 24 -&gt; 25 -&gt; 02-10 -&gt; 26 -&gt; 27 -&gt; 31 -&gt; 32 -&gt; 35</span></span></code></pre></div><p>先补 CSS、TypeScript、异步和浏览器心智,再学 React。不要上来就把所有框架都刷一遍。</p><h3 id="react-工程路线" tabindex="-1">React 工程路线 <a class="header-anchor" href="#react-工程路线" aria-label="Permalink to &quot;React 工程路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>02-10 -&gt; 22-28 -&gt; 31-35 -&gt; 40-41</span></span></code></pre></div><p>目标是能做真实业务前端:组件、状态、数据、表单、路由、性能、测试、安全、部署。</p><h3 id="vue-工程路线" tabindex="-1">Vue 工程路线 <a class="header-anchor" href="#vue-工程路线" aria-label="Permalink to &quot;Vue 工程路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>11-17 -&gt; 22-28 -&gt; 31-35 -&gt; 40-41</span></span></code></pre></div><p>Vue 主线更适合偏模板、偏产品交付的团队。Nuxt 负责把 Vue 带到 SSR / 全栈场景。</p><h3 id="进阶对照路线" tabindex="-1">进阶对照路线 <a class="header-anchor" href="#进阶对照路线" aria-label="Permalink to &quot;进阶对照路线&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>18-21 -&gt; 35 -&gt; 36 -&gt; 37 -&gt; 38 -&gt; 39</span></span></code></pre></div><p>SolidJS 用来理解细粒度响应式。Wasm、Web Components、微前端、图形这些按业务需要学,不是每个前端都必须深挖。</p><hr><h2 id="边界" tabindex="-1">边界 <a class="header-anchor" href="#边界" aria-label="Permalink to &quot;边界&quot;">​</a></h2><ul><li>不再维护低频框架主线。遇到团队内部指定技术栈时,以官方文档和项目规范为准。</li><li>不把框架版本新闻写进主线。React、Vue、Solid、Vite、Next、Nuxt 的快变内容放到 <code>版本复查清单.md</code> 维护。</li><li>不把后端、数据库、DevOps 展开成完整后端系列。这里只讲前端工程师需要完成闭环的部分。</li></ul><hr><h2 id="完结说明" tabindex="-1">完结说明 <a class="header-anchor" href="#完结说明" aria-label="Permalink to &quot;完结说明&quot;">​</a></h2><p>43 篇覆盖现代前端的核心知识图:</p><ul><li>UI 框架:React / Vue / SolidJS</li><li>基础:CSS / TypeScript / JavaScript 异步</li><li>工程:构建 / 测试 / 安全 / Node API / 数据库 / 部署</li><li>浏览器:性能 / 实时通信 / PWA / 渲染原理</li><li>专题:Wasm / Web Components / 微前端 / 图形 / a11y / i18n / 桌面 / 跨端</li></ul><p>下一步最该补的不是新框架,而是项目制教程:用 React 或 Vue 做一个真实 SaaS / 管理台 / 内容产品,把这些章节串起来。</p>`,42)])])}const x=e(s,[["render",n]]);export{u as __pageData,x as default};
